#include<bits/stdc++.h>
using namespace std;
const int N=1000000+5;
int a[N],b[N],c[N];  // a: 原始数组；b: 前缀不同数字个数；c: 数字计数数组
long long ans;       // 结果，使用long long避免溢出
/*
对于每个数字 y，我们只在它的倒数第二次出现位置进行统计
在统计时，b[i-1]包含了所有可能的 x（包括 y自身）
当 y出现3次或以上时，b[i-1]会包含 y自身，形成非法序列 (y,y,y)
而在 y倒数第三次出现时的 ans--正好抵消了这个非法计数
最终结果只包含合法的 (x,y,y)序列，其中 x ≠ y
*/
int main(){
    int i,k,n;

    // 读取输入
    for(i=1,cin>>n;i<=n;++i) cin>>a[i];

    // 第一遍扫描：计算b[i] - 前i个元素中不同数字的个数
    for(i=1,k=0;i<=n;++i){
        if(!c[a[i]]++) ++k;  // 如果a[i]是第一次出现，不同数字数k增加1
        b[i]=k;              // 记录前i个位置的不同数字数量
    }

    // 第二遍扫描：统计moo序列数量
    for(i=1;i<=n;++i){
        // 当c[a[i]]为3时，说明a[i]还剩3次出现
        // 这意味着接下来会有一个非法的(y,y,y)序列，需要扣除
        if(c[a[i]]==3) ans--;

        // 当c[a[i]]为2时，说明当前是a[i]的倒数第二次出现
        // 这是a[i]作为y时的第一个y位置
        // 此时b[i-1]表示前i-1个位置中不同数字的个数
        // 这些数字都可以作为x与当前的y形成(x,y,y)序列
        if(c[a[i]]--==2) ans+=b[i-1];
    }

    // 输出结果
    printf("%lld\n",ans);
    return 0;
}

