#include <iostream>
using namespace std;
int main() {
    long long N = 0; // 定义变量N存储输入的正整数
    cin >> N; // 读取输入的正整数N
    bool first = true; // 用于标记是否是第一次输出，第一次输出前不需要输出 *
    for (long long p = 2; p * p <= N; p++) { // 从2开始检查到sqrt(N)
        if (N % p != 0) // 如果p不能整除N，跳过
            continue;
        int cnt = 0; // 统计p出现的次数
        while (N % p == 0) { // 当p能整除N时
            cnt++; // 次数加1
            N /= p; // N除以p
        }
        if (first) { // 如果是第一次输出
            first = false; 
        } else { // 不是第一次输出，输出 * 
            cout << " * ";
        }
        cout << p; // 输出当前的素数p
        if (cnt > 1) // 如果p出现次数大于1，输出指数形式
            cout << "^" << cnt;
    }
    if (N > 1) { // 如果最后N还大于1，说明N本身是素数
        if (first) { // 如果之前没有输出过
            first = false;
        } else {
            cout << " * ";
        }
        cout << N; // 输出这个素数N
    }
    cout << endl; // 输出换行
    return 0;
}

