#include <iostream>  
#include <vector>  
#include <algorithm>  
using namespace std;  
  
int countPairs(vector<int>& nums, int c) {  
    int n = nums.size();  
    sort(nums.begin(), nums.end()); // 先对数组进行排序  
    int left = 0, right = n - 1, pairs = 0;  
      
    while (left < right) {  
        int diff = nums[right] - nums[left];  
        if (diff == c) {  
            // 如果找到了一对，尝试增加left指针，同时减去right指针（避免重复计数）  
            pairs += right - left;  
            left++;  
        } else if (diff > c) {  
            // 如果diff太大，减小right指针  
            right--;  
        } else {  
            // 如果diff太小，增加left指针  
            left++;  
        }  
    }  
      
    return pairs;  
}  
  
